#!/usr/bin/env dotnet
// friday13.cs — Friday the 13th explorer (proleptic Gregorian calendar)

// 1. Find the earliest Friday the 13th starting from 0001-01-01
DateTime earliest = DateTime.MinValue;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            if (earliest == DateTime.MinValue)
            {
                earliest = d;
                Console.WriteLine($"Earliest Friday the 13th: {d:yyyy-MM-dd}");
            }
        }
    }
}

// 2. Count Friday the 13ths in one full 400-year Gregorian cycle (years 1–400)
int count = 0;
var monthCounts = new int[12];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            count++;
            monthCounts[month - 1]++;
        }
    }
}

Console.WriteLine($"\nFriday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

Console.WriteLine("\nBreakdown by month:");
string[] names = ["Jan","Feb","Mar","Apr","May","Jun",
                  "Jul","Aug","Sep","Oct","Nov","Dec"];
for (int i = 0; i < 12; i++)
    Console.WriteLine($"  {names[i]}: {monthCounts[i],3}");

// 3. Distribution by day-of-week for the 13th (fun bonus)
Console.WriteLine("\nHow often does the 13th fall on each day? (400-year cycle)");
var dowCounts = new int[7];
for (int year = 1; year <= 400; year++)
    for (int month = 1; month <= 12; month++)
        dowCounts[(int)new DateTime(year, month, 13).DayOfWeek]++;

foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-9}: {dowCounts[(int)dow],4}");

